// expression in the page context, prints the result as JSON.
import { WebSocket } from "node:ws";
const wsUrl = process.argv[2];
const expression = process.argv[3];
if (!wsUrl || !expression) {
  console.error("usage: cdp-eval.mjs <wsUrl> <expression>");
  process.exit(2);
}
const ws = new WebSocket(wsUrl);
ws.on("open", () => {
  ws.send(
    JSON.stringify({
      id: 1,
      method: "Runtime.evaluate",
      params: {
        expression,
        awaitPromise: true,
        returnByValue: true,
      },
    })
  );
});
ws.on("message", (raw) => {
  const msg = JSON.parse(raw.toString());
  if (msg.id === 1) {
    console.log(JSON.stringify(msg.result ?? msg.error, null, 2));
    ws.close();
  }
});
ws.on("error", (err) => {
  console.error("ws-error", err.message);
  process.exit(1);
});

